class AXColorUtil {
  parse(color: string): ColorObject;
  format(color: ColorObject, format: 'rgba' | 'hex' | 'hsla' | 'hsva'): string;
  toRgba(color: string): string;
  toHex(color: string): string;
  toHsla(color: string): string;
  toHsva(color: string): string;
  lighten(color: string, amount: number): string;
  darken(color: string, amount: number): string;
  saturate(color: string, amount: number): string;
  desaturate(color: string, amount: number): string;
  mix(color1: string, color2: string, ratio: number): string;
  isValid(color: string): boolean;
  getContrast(color1: string, color2: string): number;
  getLuminance(color: string): number;
}
